#include<bits/stdc++.h>
using namespace std;
int a[20001];
int mp[150001];
int cnta[15001],cntb[15001],cntc[15001],cntd[15001];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i]);
        mp[a[i]]++;
    }
    for(int i=1;i<=n;i++)
    {
        if(mp[i]==0)
        {
            continue;
        }
        for(int j=i+1;j<=n;j++)
        {
            if(mp[j]==0)
            {
                continue;
            }
            if((j-i)%2!=0)
            {
                continue;
            }
            for(int k=j+1;k<=n;k++)
            {
                if(mp[k]==0)
                {
                    continue;
                }
                if(!((j-i)<((k-j)/3.0)))
                {
                    continue;
                }
                int l=((j-i)/2)+k;
                if(mp[l]==0)
                {
                    continue;
                }
                int cnt=mp[i]*mp[j]*mp[k]*mp[l];
                cnta[i]+=cnt;
                cntb[j]+=cnt;
                cntc[k]+=cnt;
                cntd[l]+=cnt;
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        printf("%d %d %d %d\n",cnta[a[i]],cntb[a[i]],cntc[a[i]],cntd[a[i]]);
    }
    return 0;
}
